"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { PlayIcon, StopIcon, CheckIcon } from "@phosphor-icons/react";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

interface Voice {
  /** Unique voice identifier */
  id: string;
  /** Display name */
  name: string;
  /** Optional preview audio URL */
  previewUrl?: string;
  /** Optional labels / tags (e.g., "Conversational", "Calm") */
  labels?: string[];
  /** Optional description */
  description?: string;
}

interface VoicePickerProps
  extends
    Omit<React.ComponentProps<"div">, "onSelect">,
    VariantProps<typeof pickerVariants> {
  /** List of available voices */
  voices: Voice[];
  /** Called when a voice is selected */
  onSelect?: (voice: Voice) => void;
  /** Currently selected voice ID */
  selectedId?: string;
  /** Whether to show preview play buttons. Default: true */
  showPreview?: boolean;
}

// =============================================================================
// VARIANTS
// =============================================================================

const pickerVariants = cva(
  "flex flex-col gap-1 rounded-xl border border-border bg-background p-2 overflow-y-auto",
  {
    variants: {
      size: {
        sm: "text-sm p-1.5 gap-0.5",
        md: "text-sm p-2 gap-1",
        lg: "text-base p-3 gap-1.5",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

// =============================================================================
// PREVIEW HOOK
// =============================================================================

function useAudioPreview() {
  const audioRef = React.useRef<HTMLAudioElement | null>(null);
  const [playingId, setPlayingId] = React.useState<string | null>(null);

  const play = React.useCallback((voiceId: string, url: string) => {
    // Stop any currently playing preview
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current = null;
    }

    const audio = new Audio(url);
    audioRef.current = audio;
    setPlayingId(voiceId);

    audio.onended = () => {
      setPlayingId(null);
      audioRef.current = null;
    };

    audio.onerror = () => {
      setPlayingId(null);
      audioRef.current = null;
    };

    audio.play().catch(() => {
      setPlayingId(null);
      audioRef.current = null;
    });
  }, []);

  const stop = React.useCallback(() => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current = null;
    }
    setPlayingId(null);
  }, []);

  // Cleanup on unmount
  React.useEffect(() => {
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  return { playingId, play, stop };
}

// =============================================================================
// VOICE ITEM
// =============================================================================

function VoiceItem({
  voice,
  isSelected,
  isPlaying,
  showPreview,
  onSelect,
  onPreviewPlay,
  onPreviewStop,
}: {
  voice: Voice;
  isSelected: boolean;
  isPlaying: boolean;
  showPreview: boolean;
  onSelect: () => void;
  onPreviewPlay: () => void;
  onPreviewStop: () => void;
}) {
  return (
    <div
      className={cn(
        "flex items-center gap-3 rounded-lg px-3 py-2 cursor-pointer transition-colors",
        "hover:bg-accent/50",
        isSelected && "bg-accent ring-1 ring-ring"
      )}
      onClick={onSelect}
      onKeyDown={(e) => {
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault();
          onSelect();
        }
      }}
      role="option"
      aria-selected={isSelected}
      tabIndex={0}
    >
      {/* Selection indicator */}
      <div
        className={cn(
          "size-5 shrink-0 rounded-full border-2 flex items-center justify-center transition-colors",
          isSelected
            ? "border-primary bg-primary"
            : "border-muted-foreground/30"
        )}
      >
        {isSelected && (
          <CheckIcon className="size-3 text-primary-foreground" weight="bold" />
        )}
      </div>

      {/* Voice info */}
      <div className="min-w-0 flex-1">
        <div className="font-medium truncate">{voice.name}</div>
        {voice.description && (
          <div className="text-xs text-muted-foreground truncate">
            {voice.description}
          </div>
        )}
        {voice.labels && voice.labels.length > 0 && (
          <div className="flex flex-wrap gap-1 mt-1">
            {voice.labels.map((label) => (
              <span
                key={label}
                className="inline-block rounded-full bg-muted px-2 py-0.5 text-[10px] text-muted-foreground"
              >
                {label}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* Preview button */}
      {showPreview && voice.previewUrl && (
        <button
          type="button"
          onClick={(e) => {
            e.stopPropagation();
            isPlaying ? onPreviewStop() : onPreviewPlay();
          }}
          className={cn(
            "inline-flex items-center justify-center size-8 rounded-full shrink-0 transition-colors",
            "hover:bg-accent",
            isPlaying
              ? "text-destructive"
              : "text-muted-foreground hover:text-foreground"
          )}
          aria-label={isPlaying ? "Stop preview" : "Play preview"}
        >
          {isPlaying ? (
            <StopIcon className="size-4" weight="fill" />
          ) : (
            <PlayIcon className="size-4" weight="fill" />
          )}
        </button>
      )}
    </div>
  );
}

// =============================================================================
// COMPONENT
// =============================================================================

function VoicePicker({
  voices,
  onSelect,
  selectedId,
  showPreview = true,
  size,
  className,
  ...props
}: VoicePickerProps) {
  const { playingId, play, stop } = useAudioPreview();

  return (
    <div
      data-slot="voice-picker"
      className={cn(pickerVariants({ size }), className)}
      role="listbox"
      aria-label="Select a voice"
      {...props}
    >
      {voices.length === 0 && (
        <div className="text-center text-muted-foreground/50 py-6">
          No voices available
        </div>
      )}
      {voices.map((voice) => (
        <VoiceItem
          key={voice.id}
          voice={voice}
          isSelected={voice.id === selectedId}
          isPlaying={playingId === voice.id}
          showPreview={showPreview}
          onSelect={() => onSelect?.(voice)}
          onPreviewPlay={() => play(voice.id, voice.previewUrl!)}
          onPreviewStop={stop}
        />
      ))}
    </div>
  );
}

VoicePicker.displayName = "VoicePicker";

export { VoicePicker, pickerVariants };
export type { VoicePickerProps, Voice };
